&lt;p&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot; font-weight: 700;&quot;&gt;Themes of International Yoga Day :&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;2015: Yoga for Harmony and Peace&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;2016: Yoga for the achievement of the Sustainable Development Goals&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;2017: Yoga for Health&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;2018: Yoga for Peace&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;2019: Yoga for Heart&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;2020: Yoga at Home and Yoga with Family&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;2021:&amp;nbsp;Yoga For Wellness&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;2022:&amp;nbsp;Yoga for Humanity&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;2023:&amp;nbsp;&lt;/span&gt;&lt;strong&gt;Yoga for Vasudhaiva Kutumbakam&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;2024: Yoga for Self and Society&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;On 11&lt;span style=&quot;position: relative; line-height: 0; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;th&lt;/span&gt;&amp;nbsp;December 2014&lt;/span&gt;, the United Nations proclaimed&amp;nbsp;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;21 June&lt;/span&gt;&lt;/u&gt;&amp;nbsp;as the International Day of Yoga by&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;resolution 69/131.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;idea&lt;/span&gt;&amp;nbsp;of the International Day of Yoga was proclaimed by the current Prime Minister of India, Narendra Modi, during his speech at the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;United Nations General Assembly in 2014&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;International Yoga Day&lt;/span&gt;&amp;nbsp;is celebrated every year on&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;21 June&lt;/span&gt;&amp;nbsp;to raise awareness worldwide about the benefits of Yoga in Daily Life.&lt;/li&gt;
	&lt;li&gt;June 21, also called the summer solstice, is the longest day of the year.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Visakhapatnam&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;The 28th National Conference on e-Governance (NCeG) 2025 is being held in Visakhapatnam from 22 to 23 September 2025.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;The theme of the conference is &amp;ldquo;Viksit Bharat: Civil Service and Digital Transformation&amp;rdquo;.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The conference will feature 6 plenary sessions and 6 breakout sessions, with about 70 speakers from diverse backgrounds.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Dr. Jitendra Singh and N. Chandrababu Naidu will inaugurate the event.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The conference is being organised by the Department of Administrative Reforms &amp;amp; Public Grievances (DARPG) and MeitY in collaboration with the Government of Andhra Pradesh.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;About the Conference&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;The conference is a platform to discuss e-governance practices and digital transformation in the Indian civil service.&lt;/li&gt;
		&lt;li&gt;It aims to bring together experts, policymakers, and stakeholders to share knowledge and improve governance practices.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Notable Speakers&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;Dr. Jitendra Singh &amp;ndash; Minister of State (Independent Charge) for Ministry of Personnel, Public Grievances &amp;amp; Pensions&lt;/li&gt;
		&lt;li&gt;N. Chandrababu Naidu &amp;ndash; Chief Minister of Andhra Pradesh&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;K&amp;nbsp;&lt;/strong&gt;&lt;/u&gt;&lt;u&gt;&lt;strong&gt;D&lt;/strong&gt; &lt;/u&gt;&lt;strong&gt;&lt;u&gt;Jadhav&lt;/u&gt;&lt;/strong&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;K&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;D&lt;/strong&gt; &lt;strong&gt;Jadhav&lt;/strong&gt; was an Indian wrestler.

	&lt;ul&gt;
		&lt;li&gt;He won a &lt;strong&gt;bronze&lt;/strong&gt; &lt;strong&gt;medal&lt;/strong&gt; in the&amp;nbsp;&lt;strong&gt;Summer&lt;/strong&gt; &lt;strong&gt;Olympics&lt;/strong&gt; in 1952.&lt;/li&gt;
		&lt;li&gt;He was awarded the Arjuna Award posthumously in 2001.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Milkha&lt;/strong&gt; &lt;strong&gt;Singh&lt;/strong&gt;&amp;nbsp;is an Indian athlete.
	&lt;ul&gt;
		&lt;li&gt;He is known as&amp;nbsp;&amp;#39;&lt;strong&gt;The&lt;/strong&gt; &lt;strong&gt;Flying&lt;/strong&gt; &lt;strong&gt;Sikh&lt;/strong&gt;&amp;#39;.&lt;/li&gt;
		&lt;li&gt;He won &lt;strong&gt;four&lt;/strong&gt; &lt;strong&gt;Gold&lt;/strong&gt; &lt;strong&gt;medals&lt;/strong&gt; in Asian games.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Karnam&lt;/strong&gt; &lt;strong&gt;Malleshwari&lt;/strong&gt; is an Indian &lt;strong&gt;weightlifter&lt;/strong&gt;.
	&lt;ul&gt;
		&lt;li&gt;She was the &lt;strong&gt;first&lt;/strong&gt; &lt;strong&gt;Indian&lt;/strong&gt; &lt;strong&gt;woman&lt;/strong&gt; to win a medal at the &lt;strong&gt;Olympics&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;She was awarded the&amp;nbsp;&lt;strong&gt;Rajiv&lt;/strong&gt; &lt;strong&gt;Gandhi&lt;/strong&gt; &lt;strong&gt;Khel&lt;/strong&gt; &lt;strong&gt;Ratna&lt;/strong&gt; &lt;strong&gt;award&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;P&lt;/strong&gt;.&lt;strong&gt;T&lt;/strong&gt; &lt;strong&gt;Usha&lt;/strong&gt; is one the most successful &lt;strong&gt;athlete&lt;/strong&gt; , also known as &amp;#39;&lt;strong&gt;The&lt;/strong&gt; &lt;strong&gt;Golden&lt;/strong&gt; &lt;strong&gt;Girl&lt;/strong&gt;&amp;#39;.
	&lt;ul&gt;
		&lt;li&gt;She won &lt;b&gt;4&lt;/b&gt;&amp;nbsp;&lt;strong&gt;gold&lt;/strong&gt; &lt;strong&gt;medals&lt;/strong&gt; in the &lt;strong&gt;Asian&lt;/strong&gt; &lt;strong&gt;Games&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The Correct answer is &lt;u&gt;&lt;strong&gt;Heavy and basic industries&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: (33, 37, 41);&quot;&gt;
	&lt;li&gt;The &lt;strong&gt;Second Five-Year Plan (1956-61)&lt;/strong&gt; of India, formulated under the guidance of &lt;strong&gt;P.C. Mahalanobis&lt;/strong&gt;, emphasized rapid industrialization as the key to economic development.&lt;/li&gt;
	&lt;li&gt;The main focus of the plan was on the development of &lt;strong&gt;heavy and basic industries&lt;/strong&gt;, such as steel, machinery, and infrastructure, which were considered essential for laying the foundation of a modern industrial economy.&lt;/li&gt;
	&lt;li&gt;This plan followed the &lt;strong&gt;Mahalanobis model&lt;/strong&gt;, which prioritized the production of capital goods over consumer goods to enhance long-term growth.&lt;/li&gt;
	&lt;li&gt;Key projects initiated during this period include the establishment of &lt;strong&gt;steel plants&lt;/strong&gt; at Bhilai, Rourkela, and Durgapur, which were built with the assistance of the Soviet Union, Germany, and the UK, respectively.&lt;/li&gt;
	&lt;li&gt;The plan also focused on strengthening the &lt;strong&gt;public sector&lt;/strong&gt; and creating a self-reliant economy by reducing dependency on foreign imports.&lt;/li&gt;
	&lt;li&gt;The emphasis on heavy industries was aimed at creating employment opportunities, boosting the production of essential goods, and accelerating the pace of economic progress in the country.&lt;/li&gt;
	&lt;li&gt;By prioritizing heavy and basic industries, the plan sought to achieve a balanced regional development and address issues of economic disparity in the country.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Education and health&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;Although &lt;strong&gt;education and health&lt;/strong&gt; were recognized as important sectors, they were not the top priority under the Second Five-Year Plan.&lt;/li&gt;
		&lt;li&gt;The focus on education and health gained prominence in later plans, especially under the &lt;strong&gt;Fourth and Fifth Five-Year Plans&lt;/strong&gt;, to improve human capital and social development.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Agriculture&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;Agriculture&lt;/strong&gt; was prioritized under the &lt;strong&gt;First Five-Year Plan (1951-56)&lt;/strong&gt; due to the immediate need to address food shortages post-independence.&lt;/li&gt;
		&lt;li&gt;However, during the Second Five-Year Plan, agriculture received secondary importance as the emphasis shifted toward industrialization.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Small-scale industries&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;While the &lt;strong&gt;Second Five-Year Plan&lt;/strong&gt; did include provisions to promote &lt;strong&gt;small-scale industries&lt;/strong&gt;, these were not the central focus.&lt;/li&gt;
		&lt;li&gt;Small-scale industries were considered crucial for generating employment and supporting rural development, but the major investments were directed toward heavy and basic industries.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The Correct Answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;Kolkata&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;PM Modi Reviews Armed Forces at 16th Combined Commanders&amp;rsquo; Conference.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;309&quot; data-start=&quot;167&quot;&gt;
	&lt;p data-end=&quot;309&quot; data-start=&quot;169&quot;&gt;PM &lt;strong data-end=&quot;189&quot; data-start=&quot;172&quot;&gt;Narendra Modi&lt;/strong&gt; reviewed security and preparedness at the &lt;strong data-end=&quot;278&quot; data-start=&quot;232&quot;&gt;16th Combined Commanders&amp;rsquo; Conference (CCC)&lt;/strong&gt; in &lt;strong data-end=&quot;306&quot; data-start=&quot;282&quot;&gt;Kolkata, West Bengal&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;405&quot; data-start=&quot;310&quot;&gt;
	&lt;p data-end=&quot;405&quot; data-start=&quot;312&quot;&gt;He was briefed on &lt;strong data-end=&quot;351&quot; data-start=&quot;330&quot;&gt;Operation Sindoor&lt;/strong&gt;, emerging technologies, and future warfare tactics.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;505&quot; data-start=&quot;406&quot;&gt;
	&lt;p data-end=&quot;505&quot; data-start=&quot;408&quot;&gt;Modi praised Armed Forces for roles in &lt;strong data-end=&quot;502&quot; data-start=&quot;447&quot;&gt;anti-piracy, HADR, evacuations, and nation building&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;616&quot; data-start=&quot;506&quot;&gt;
	&lt;p data-end=&quot;616&quot; data-start=&quot;508&quot;&gt;&lt;strong data-end=&quot;543&quot; data-start=&quot;508&quot;&gt;2025 declared &amp;lsquo;Year of Reforms&amp;rsquo;&lt;/strong&gt; in defence, focusing on &lt;strong data-end=&quot;613&quot; data-start=&quot;568&quot;&gt;jointness, Aatmanirbharta, and innovation&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;698&quot; data-start=&quot;617&quot;&gt;
	&lt;p data-end=&quot;698&quot; data-start=&quot;619&quot;&gt;&lt;strong data-end=&quot;628&quot; data-start=&quot;619&quot;&gt;Theme&lt;/strong&gt; of CCC 2025: &lt;strong data-end=&quot;695&quot; data-start=&quot;642&quot;&gt;&amp;lsquo;Year of Reforms &amp;ndash; Transformation for the Future&amp;rsquo;&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;812&quot; data-start=&quot;699&quot;&gt;
	&lt;p data-end=&quot;812&quot; data-start=&quot;701&quot;&gt;Conference held &lt;strong data-end=&quot;741&quot; data-start=&quot;717&quot;&gt;once every two years&lt;/strong&gt;, bringing together political leadership and top military commanders.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;913&quot; data-start=&quot;813&quot;&gt;
	&lt;p data-end=&quot;913&quot; data-start=&quot;815&quot;&gt;Defence Minister will address on &lt;strong data-end=&quot;864&quot; data-start=&quot;848&quot;&gt;September 16&lt;/strong&gt;, and the Chief of Defence on &lt;strong data-end=&quot;910&quot; data-start=&quot;894&quot;&gt;September 17&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1012&quot; data-start=&quot;914&quot;&gt;
	&lt;p data-end=&quot;1012&quot; data-start=&quot;916&quot;&gt;Discussions include &lt;strong data-end=&quot;991&quot; data-start=&quot;936&quot;&gt;structural, administrative, and operational reforms&lt;/strong&gt; for modernisation.&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p data-end=&quot;1012&quot; data-start=&quot;916&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;1131&quot; data-start=&quot;1048&quot;&gt;
	&lt;p data-end=&quot;1131&quot; data-start=&quot;1050&quot;&gt;&lt;strong data-end=&quot;1061&quot; data-start=&quot;1050&quot;&gt;Kolkata&lt;/strong&gt;: Capital of &lt;strong data-end=&quot;1089&quot; data-start=&quot;1074&quot;&gt;West Bengal&lt;/strong&gt;, located on the banks of river Hooghly.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1218&quot; data-start=&quot;1132&quot;&gt;
	&lt;p data-end=&quot;1218&quot; data-start=&quot;1134&quot;&gt;&lt;strong data-end=&quot;1152&quot; data-start=&quot;1134&quot;&gt;Aatmanirbharta&lt;/strong&gt;: Government initiative for self-reliance in defence production.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1368&quot; data-start=&quot;1219&quot;&gt;
	&lt;p data-end=&quot;1368&quot; data-start=&quot;1221&quot;&gt;&lt;strong data-end=&quot;1275&quot; data-start=&quot;1221&quot;&gt;Humanitarian Assistance and Disaster Relief (HADR)&lt;/strong&gt;: India often provides aid to neighbours (Nepal earthquake 2015, Turkey earthquakes, etc.).&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1479&quot; data-start=&quot;1369&quot;&gt;
	&lt;p data-end=&quot;1479&quot; data-start=&quot;1371&quot;&gt;&lt;strong data-end=&quot;1406&quot; data-start=&quot;1371&quot;&gt;Combined Commanders&amp;rsquo; Conference&lt;/strong&gt;: First held in &lt;strong data-end=&quot;1430&quot; data-start=&quot;1422&quot;&gt;1953&lt;/strong&gt;, serves as the highest defence dialogue forum.&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;

