&lt;p data-end=&quot;63&quot; data-start=&quot;49&quot;&gt;&lt;strong data-end=&quot;63&quot; data-start=&quot;49&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p data-end=&quot;170&quot; data-start=&quot;65&quot;&gt;&lt;strong data-end=&quot;94&quot; data-start=&quot;65&quot;&gt;4. Dandekar &amp;amp; Rath (1971)&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;170&quot; data-start=&quot;65&quot;&gt;Earliest landmark study proposing a calorie-based poverty line for India.&lt;/li&gt;
&lt;/ul&gt;

&lt;p data-end=&quot;310&quot; data-start=&quot;172&quot;&gt;&lt;strong data-end=&quot;205&quot; data-start=&quot;172&quot;&gt;1. Lakdawala Committee (1993)&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;310&quot; data-start=&quot;172&quot;&gt;Planning Commission expert group; recommended state-specific poverty lines using 2400/2100 kcal norms.&lt;/li&gt;
&lt;/ul&gt;

&lt;p data-end=&quot;440&quot; data-start=&quot;312&quot;&gt;&lt;strong data-end=&quot;345&quot; data-start=&quot;312&quot;&gt;3. Tendulkar Committee (2009)&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;440&quot; data-start=&quot;312&quot;&gt;Shifted from calorie norms to a broader consumption basket; new poverty lines based on MPCE.&lt;/li&gt;
&lt;/ul&gt;

&lt;p data-end=&quot;573&quot; data-is-last-node=&quot;&quot; data-is-only-node=&quot;&quot; data-start=&quot;442&quot;&gt;&lt;strong data-end=&quot;479&quot; data-start=&quot;442&quot;&gt;2. Rangarajan Committee (2012&amp;ndash;14)&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;573&quot; data-is-last-node=&quot;&quot; data-is-only-node=&quot;&quot; data-start=&quot;442&quot;&gt;Reviewed measurement again; proposed higher poverty thresholds and a different methodology.&lt;/li&gt;
&lt;/ul&gt;
